'use client'

import { WelcomeBanner } from '../components/dashboard/welcome-banner'
import { StatsSection } from '../components/dashboard/stats-card'
import { AnalyticsSection } from '../components/dashboard/analytics-charts'
import { SmartSuggestions, ImpactSection } from '../components/dashboard/smart-suggestions'
import { ActivityFeed, NGORequestsPanel } from '../components/dashboard/activity-feed'

export default function DonorDashboard() {
  return (
    <div className="w-full">
      {/* Colorful Food Background Hero Section */}
      <div 
        className="h-64 rounded-2xl mb-8 relative overflow-hidden"
        style={{
          backgroundImage: 'url(/food-background.jpg)',
          backgroundSize: 'cover',
          backgroundPosition: 'center',
        }}
      >
        {/* Overlay for depth */}
        <div className="absolute inset-0 bg-gradient-to-r from-black/50 via-transparent to-black/50" />
        <div className="absolute inset-0 bg-gradient-to-b from-emerald-900/30 to-transparent" />
        
        {/* Text overlay */}
        <div className="absolute inset-0 flex items-center justify-center">
          <div className="text-center text-white">
            <h2 className="text-4xl font-bold mb-2">Colorful Impact, Real Change</h2>
            <p className="text-lg text-white/90">Join thousands rescuing food and feeding communities</p>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto">
      {/* Welcome Banner */}
      <WelcomeBanner />

      {/* Stats Section */}
      <StatsSection />

      {/* Analytics Charts */}
      <AnalyticsSection />

      {/* Smart Suggestions */}
      <SmartSuggestions />

      {/* Activity & Requests Section */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
        <div className="lg:col-span-1">
          <ActivityFeed />
        </div>
        <div className="lg:col-span-2">
          <NGORequestsPanel />
        </div>
      </div>

      {/* Impact Section */}
      <ImpactSection />
      </div>
    </div>
  )
}
